@js:
var result = [];
java.toast("🔥正在刷新列表,请稍等！");
var push = (title, url, size) => result.push({
    "title": title,
    "url": url,
    "style": {
        "layout_flexGrow": 1,
        "layout_flexBasisPercent": size
    }
});
var baseUrl = "https://www.zhenhunxiaoshuo.com/chaxun.html";
var tag = java.ajax(baseUrl);
if (tag) {
    var a = org.jsoup.Jsoup.parse(tag).select(".col-md-9 a");
    push("🔥作者集🔥", null, 1);
    for (var i = 0; i < a.length ; i++) {
        var title = a[i].text();
        var url = a[i].attr("href");
        var size = 0.25;
        title = String(title).replace(/\s/g, "");
        push(title, url, size);
    }
} else {
  java.toast("🤔列表刷新失败！！！");     
} 
JSON.stringify(result);

@js:
const u = source.key, list = [];
const push = (title, url, flex) => list.push({
  title: title,
  url: url,
  style: {
    layout_flexGrow: 1,
    layout_flexBasisPercent: flex
  }
});
const getDoc = url => org.jsoup.Jsoup.parse(java.ajax(url));
const doc = getDoc(u);
push("・分类・", "", 1);
doc.select('.menu a').forEach(e => push(e.text(), e.attr('href') + "<,index_{{page}}.html>", null));
push("・标签・", "", 1);
doc.select('.panel-default a').forEach(e => push(e.text(), String(e.attr('href')).replace(/\d+\.html$/, '{{page-1}}.html'), null));
push("・书单・", "", 1);
const sUrl = u + "/shudan", sDoc = getDoc(sUrl);
const total = +((sDoc.select('.m-page .disabled').text().match(/\/(\d+)/) || [,0])[1]);
for (let i = 1; i <= total; ++i) {
  let page = i == 1 ? "": `/index_${i}.html`;
  getDoc(sUrl + page).select('.panel-warning .list-group-item a').forEach(e => push(e.text(), e.attr('href'), null));
}
JSON.stringify(list);

